mapper.select:
SELECT * FROM saf.tn_saf_airprt_purch
WHERE airprt_cd = #{airprtId} AND rprt_yr = #{rprtYr}
  AND oprtr_id = #{oprtrId} AND purch_sn = #{purchSn}

SELECT * FROM saf.tn_saf_airprt_purch
WHERE use_end_dt > NOW()
AND oprtr_id = #{oprtrId}
AND rprt_yr = #{rprtYr}
ORDER BY rprt_yr DESC, airprt_cd, purch_sn

SELECT COALESCE(MAX(purch_sn), 0)
FROM saf.tn_saf_airprt_purch
WHERE airprt_cd = #{airprtId} AND rprt_yr = #{rprtYr} AND oprtr_id = #{oprtrId}

mapper.insert:
INSERT INTO saf.tn_saf_airprt_purch (
    airprt_cd, rprt_yr, oprtr_id, purch_sn,
    sply_co_info, batch_id, purch_qty, fuel_type_cd, orgn_info,
    frst_reg_dt, frst_reg_user_id, last_chg_dt, last_chg_user_id
) VALUES (
    #{airprtId}, #{rprtYr}, #{oprtrId}, #{purchSn},
    #{splyCoInfo}, #{batchId}, #{purchQty}, #{fuelTypeCd}, #{orgnInfo},
    NOW(), #{frstRegUserId}, NOW(), #{lastChgUserId}
)

mapper.update:
UPDATE saf.tn_saf_airprt_purch
SET sply_co_info     = #{splyCoInfo},
    batch_id         = #{batchId},
    purch_qty        = #{purchQty},
    fuel_type_cd     = #{fuelTypeCd},
    orgn_info        = #{orgnInfo},
    last_chg_dt      = NOW(),
    last_chg_user_id = #{lastChgUserId}
WHERE airprt_cd = #{airprtId} AND rprt_yr = #{rprtYr}
  AND oprtr_id = #{oprtrId} AND purch_sn = #{purchSn}

mapper.delete:
DELETE FROM saf.tn_saf_airprt_purch
WHERE airprt_cd = #{airprtId} AND rprt_yr = #{rprtYr}
  AND oprtr_id = #{oprtrId} AND purch_sn = #{purchSn}

mapper.select:
SELECT COALESCE(SUM(purch_qty), 0)
FROM saf.tn_saf_airprt_purch
WHERE oprtr_id = #{oprtrId} AND rprt_yr = #{rprtYr}
